### Dashboard Integration

The dashboard uses monitor data to show visual indicators:

```go
// internal/robot/dashboard_indicators.go

type HealthIndicator struct {
    Pane           int
    AgentType      string
    ContextPct     *float64
    ContextTrend   string
    ProviderPct    *float64
    HealthColor    string // green, yellow, orange, red
}

func getHealthColor(contextPct, providerPct *float64, isRateLimited bool) string {
    if isRateLimited {
        return "red"
    }

    if contextPct != nil {
        switch {
        case *contextPct < 15:
            return "red"
        case *contextPct < 25:
            return "orange"
        case *contextPct < 40:
            return "yellow"
        }
    }

    if providerPct != nil && *providerPct >= 80 {
        return "orange"
    }

    return "green"
}

// Progress bar rendering for TUI
func renderContextBar(pct float64) string {
    // 20-char bar: [████████░░░░░░░░░░░░]
    filled := int(pct / 5)
    empty := 20 - filled

    var bar strings.Builder
    bar.WriteString("[")
    for i := 0; i < filled; i++ {
        bar.WriteString("█")
    }
    for i := 0; i < empty; i++ {
        bar.WriteString("░")
    }
    bar.WriteString("]")
    return bar.String()
}
